/**
 * SPEC-048: back contextual del detalle de entrevista — «Volver» navega a la
 * página del grupo (/discoveries/:discoveryId/groups/:groupId, construida con
 * los datos de la propia entrevista) cuando la entrevista tiene
 * interviewGroupId, y al detalle global directo /companies/:companyId (sin
 * redirect legado) cuando no lo tiene; si el grupo fue borrado después de
 * cargar la página, el back aterriza en la página del grupo y es SU error
 * state (SPEC-046) el que responde con «Volver al discovery», sin crash.
 * Generated by QA Dev agent.
 *
 * Arnés: InterviewDetailPage en su ruta anidada real con probes de destino
 * (getInterview/getCompany mockeados); para el caso del grupo borrado se
 * monta la InterviewGroupDetailPage REAL con listInterviewGroups vacío.
 */
import type { ReactElement } from 'react'
import { render, screen, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { InterviewDetailPage } from '@/pages/InterviewDetailPage'
import { InterviewGroupDetailPage } from '@/pages/InterviewGroupDetailPage'
import type { Company, Interview } from '@/types/domain'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

const COMPANY: Company = {
  id: 'c-1',
  name: 'Acme Corp',
  website: null,
  linkedinUrl: null,
  context: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

const INTERVIEW: Interview = {
  id: 'i-1',
  discoveryId: 'd-1',
  companyId: 'c-1',
  contactIds: [],
  interviewGroupId: null,
  templateId: null,
  title: 'Discovery con Acme',
  status: 'draft',
  scriptMarkdown: null,
  objectives: [],
  wavPath: null,
  transcriptPath: null,
  createdAt: '2026-07-04T10:00:00.000Z',
  updatedAt: '2026-07-04T10:00:00.000Z'
}

/** Entrevista perteneciente al grupo g-1 de su discovery d-1. */
const GROUPED_INTERVIEW: Interview = { ...INTERVIEW, interviewGroupId: 'g-1' }

/**
 * Monta la página del detalle en su ruta anidada real. Destinos del back como
 * probes; el caso «grupo borrado» sustituye el probe del grupo por la página
 * real (groupElement).
 */
function renderDetail(groupElement?: ReactElement): RenderResult {
  return render(
    <TooltipProvider>
      <MemoryRouter initialEntries={['/discoveries/d-1/companies/c-1/interviews/i-1']}>
        <Routes>
          <Route
            path="/discoveries/:discoveryId/companies/:companyId/interviews/:interviewId"
            element={<InterviewDetailPage />}
          />
          <Route
            path="/discoveries/:discoveryId/groups/:groupId"
            element={groupElement ?? <div>GROUP_PROBE</div>}
          />
          <Route path="/companies/:companyId" element={<div>COMPANY_PROBE</div>} />
        </Routes>
      </MemoryRouter>
      <Toaster />
    </TooltipProvider>
  )
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.getCompany).mockResolvedValue({ ok: true, data: COMPANY })
  vi.mocked(mockApi.api.db.getInterview).mockResolvedValue({ ok: true, data: INTERVIEW })
})

describe('InterviewDetailPage (SPEC-048 contextual back)', () => {
  // SPEC-048 · AC-10 (con interviewGroupId → página del grupo, construida con
  // discoveryId + interviewGroupId de la propia entrevista)
  it('navigates to the group page on "Volver" when the interview belongs to a group', async () => {
    vi.mocked(mockApi.api.db.getInterview).mockResolvedValue({
      ok: true,
      data: GROUPED_INTERVIEW
    })
    const user = userEvent.setup()
    renderDetail()

    await screen.findByRole('heading', { name: 'Discovery con Acme', level: 1 })
    await user.click(screen.getByRole('button', { name: 'Volver' }))

    expect(await screen.findByText('GROUP_PROBE')).toBeInTheDocument()
  })

  // SPEC-048 · AC-11 (sin grupo → detalle global directo /companies/:companyId,
  // sin pasar por el redirect legado de SPEC-044)
  it('navigates to the direct global company detail on "Volver" when the interview has no group', async () => {
    const user = userEvent.setup()
    renderDetail()

    await screen.findByRole('heading', { name: 'Discovery con Acme', level: 1 })
    await user.click(screen.getByRole('button', { name: 'Volver' }))

    expect(await screen.findByText('COMPANY_PROBE')).toBeInTheDocument()
  })

  // SPEC-048 · AC-12 (grupo borrado tras cargar la página: el back aterriza
  // en la página del grupo y su error state SPEC-046 muestra «Volver al
  // discovery» — sin crash ni lógica extra en el detalle)
  it('lands on the group page error state with the "Volver al discovery" link when the group was deleted after load', async () => {
    vi.mocked(mockApi.api.db.getInterview).mockResolvedValue({
      ok: true,
      data: GROUPED_INTERVIEW
    })
    // El grupo ya no existe: el listado del discovery vuelve vacío (default
    // del mock, explícito aquí por legibilidad)
    vi.mocked(mockApi.api.db.listInterviewGroups).mockResolvedValue({ ok: true, data: [] })
    const user = userEvent.setup()
    renderDetail(<InterviewGroupDetailPage />)

    await screen.findByRole('heading', { name: 'Discovery con Acme', level: 1 })
    await user.click(screen.getByRole('button', { name: 'Volver' }))

    expect(await screen.findByText('Grupo no encontrado')).toBeInTheDocument()
    expect(screen.getByRole('link', { name: 'Volver al discovery' })).toHaveAttribute(
      'href',
      '/discoveries/d-1'
    )
  })
})
